import React, { useEffect, useState, useCallback } from 'react';
import type { AdminSectionProps } from '../types';
import type { TokenRecord } from '../../types';

interface TokenFormData {
  mint: string; symbol: string; name: string; decimals: string;
  logoUrl: string; coingeckoId: string; categories: string;
}

const emptyForm: TokenFormData = {
  mint: '', symbol: '', name: '', decimals: '9',
  logoUrl: '', coingeckoId: '', categories: '',
};

export function TokenRegistryPanel({ pluginContext }: AdminSectionProps) {
  const [tokens, setTokens] = useState<TokenRecord[]>([]);
  const [search, setSearch] = useState('');
  const [showAdd, setShowAdd] = useState(false);
  const [editMint, setEditMint] = useState<string | null>(null);
  const [form, setForm] = useState<TokenFormData>(emptyForm);
  const [error, setError] = useState<string | null>(null);

  const headers = {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${pluginContext.getAccessToken()}`,
  };
  const base = pluginContext.serverUrl;

  const refresh = useCallback(() => {
    fetch(`${base}/admin/tokens`, { headers })
      .then(r => r.json()).then(d => setTokens(d.tokens ?? [])).catch(() => {});
  }, [base]);

  useEffect(() => { refresh(); }, [refresh]);

  const handleAdd = async () => {
    setError(null);
    const body = {
      mint: form.mint, symbol: form.symbol, name: form.name,
      decimals: parseInt(form.decimals) || 9,
      logoUrl: form.logoUrl || undefined,
      coingeckoId: form.coingeckoId || undefined,
      categories: form.categories ? form.categories.split(',').map(s => s.trim()) : [],
    };
    const resp = await fetch(`${base}/admin/tokens`, { method: 'POST', headers, body: JSON.stringify(body) });
    if (!resp.ok) { const d = await resp.json().catch(() => ({})); setError(d.error?.message ?? 'Failed'); return; }
    setForm(emptyForm); setShowAdd(false); refresh();
  };

  const handleEdit = async () => {
    if (!editMint) return;
    setError(null);
    const body: Record<string, unknown> = {};
    if (form.name) body.name = form.name;
    if (form.symbol) body.symbol = form.symbol;
    if (form.logoUrl) body.logoUrl = form.logoUrl;
    if (form.coingeckoId) body.coingeckoId = form.coingeckoId;
    if (form.categories) body.categories = form.categories.split(',').map(s => s.trim());
    const resp = await fetch(`${base}/admin/tokens/${editMint}`, { method: 'PATCH', headers, body: JSON.stringify(body) });
    if (!resp.ok) { const d = await resp.json().catch(() => ({})); setError(d.error?.message ?? 'Failed'); return; }
    setEditMint(null); setForm(emptyForm); refresh();
  };

  const handleDelete = async (mint: string, symbol: string) => {
    if (!confirm(`Delete ${symbol} (${mint.slice(0, 8)}...)?`)) return;
    await fetch(`${base}/admin/tokens/${mint}`, { method: 'DELETE', headers });
    refresh();
  };

  const startEdit = (t: TokenRecord) => {
    setEditMint(t.mint);
    setForm({ mint: t.mint, symbol: t.symbol, name: t.name, decimals: String(t.decimals), logoUrl: t.logoUrl ?? '', coingeckoId: t.coingeckoId ?? '', categories: t.categories.join(', ') });
    setShowAdd(false);
  };

  const filtered = tokens.filter(t =>
    !search || t.symbol.toLowerCase().includes(search.toLowerCase()) || t.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="ct-space-y-4">
      <div className="ct-flex ct-items-center ct-justify-between">
        <h2 className="ct-text-xl ct-font-semibold">Token Registry</h2>
        <div className="ct-flex ct-items-center ct-gap-2">
          <span className="ct-text-sm ct-text-[hsl(var(--cedros-muted-foreground))]">{tokens.length} tokens</span>
          <button onClick={() => { setShowAdd(!showAdd); setEditMint(null); setForm(emptyForm); }}
            className="ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ct-bg-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-primary-foreground))]">
            {showAdd ? 'Cancel' : '+ Add Token'}
          </button>
        </div>
      </div>

      {/* Add / Edit form */}
      {(showAdd || editMint) && (
        <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4 ct-space-y-3">
          <h3 className="ct-text-sm ct-font-medium">{editMint ? `Edit ${form.symbol}` : 'Add Token'}</h3>
          {error && <div className="ct-text-xs ct-text-red-400">{error}</div>}
          <div className="ct-grid ct-grid-cols-2 ct-gap-2">
            {!editMint && (
              <input value={form.mint} onChange={e => setForm({ ...form, mint: e.target.value })} placeholder="Mint address"
                className="ct-col-span-2 ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            )}
            <input value={form.symbol} onChange={e => setForm({ ...form, symbol: e.target.value })} placeholder="Symbol (e.g. SOL)"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Name (e.g. Solana)"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <input value={form.decimals} onChange={e => setForm({ ...form, decimals: e.target.value })} placeholder="Decimals"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <input value={form.logoUrl} onChange={e => setForm({ ...form, logoUrl: e.target.value })} placeholder="Logo URL"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <input value={form.coingeckoId} onChange={e => setForm({ ...form, coingeckoId: e.target.value })} placeholder="CoinGecko ID"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <input value={form.categories} onChange={e => setForm({ ...form, categories: e.target.value })} placeholder="Categories (comma-separated)"
              className="ct-px-2 ct-py-1.5 ct-text-sm ct-rounded ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
          <button onClick={editMint ? handleEdit : handleAdd}
            className="ct-px-4 ct-py-2 ct-rounded ct-text-sm ct-font-medium ct-bg-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-primary-foreground))]">
            {editMint ? 'Save Changes' : 'Add Token'}
          </button>
        </div>
      )}

      <input type="text" value={search} onChange={e => setSearch(e.target.value)} placeholder="Search tokens..."
        className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />

      <table className="ct-w-full ct-text-sm">
        <thead>
          <tr className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-border-b ct-border-[hsl(var(--cedros-border))]">
            <th className="ct-text-left ct-py-2">Token</th>
            <th className="ct-text-left ct-py-2">Mint</th>
            <th className="ct-text-left ct-py-2">Dec</th>
            <th className="ct-text-left ct-py-2">Categories</th>
            <th className="ct-text-right ct-py-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map(t => (
            <tr key={t.mint} className="ct-border-b ct-border-[hsl(var(--cedros-border))]">
              <td className="ct-py-2 ct-flex ct-items-center ct-gap-2">
                {t.logoUrl && <img src={t.logoUrl} className="ct-w-5 ct-h-5 ct-rounded-full" alt="" />}
                <span className="ct-font-medium">{t.symbol}</span>
                <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">{t.name}</span>
              </td>
              <td className="ct-py-2 ct-font-mono ct-text-xs">{t.mint.slice(0, 8)}...</td>
              <td className="ct-py-2">{t.decimals}</td>
              <td className="ct-py-2 ct-space-x-1">
                {t.categories.map(c => (
                  <span key={c} className="ct-px-2 ct-py-0.5 ct-rounded ct-text-xs ct-bg-[hsl(var(--cedros-muted))]">{c}</span>
                ))}
              </td>
              <td className="ct-py-2 ct-text-right ct-space-x-2">
                <button onClick={() => startEdit(t)} className="ct-text-xs ct-text-blue-400 hover:ct-text-blue-300">Edit</button>
                <button onClick={() => handleDelete(t.mint, t.symbol)} className="ct-text-xs ct-text-red-400 hover:ct-text-red-300">Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
