import React, { useEffect, useState, useCallback } from 'react';
import type { AdminSectionProps } from '../types';

export function MonitorPanel({ pluginContext }: AdminSectionProps) {
  const [status, setStatus] = useState<any>(null);
  const headers = { 'Authorization': `Bearer ${pluginContext.getAccessToken()}` };
  const base = pluginContext.serverUrl;

  const refresh = useCallback(() => {
    fetch(`${base}/admin/monitor/status`, { headers }).then(r => r.json()).then(setStatus).catch(() => {});
  }, [base]);

  useEffect(() => { refresh(); const i = setInterval(refresh, 5000); return () => clearInterval(i); }, [refresh]);

  const pause = () => fetch(`${base}/admin/monitor/pause`, { method: 'POST', headers }).then(refresh);
  const resume = () => fetch(`${base}/admin/monitor/resume`, { method: 'POST', headers }).then(refresh);

  return (
    <div className="ct-space-y-4">
      <div className="ct-flex ct-items-center ct-justify-between">
        <h2 className="ct-text-xl ct-font-semibold">Price Monitor</h2>
        {status && (
          <div className="ct-flex ct-gap-2">
            {status.paused ? (
              <button onClick={resume} className="ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ct-bg-green-500/10 ct-text-green-400">Resume</button>
            ) : (
              <button onClick={pause} className="ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ct-bg-red-500/10 ct-text-red-400">Pause</button>
            )}
          </div>
        )}
      </div>
      {status && (
        <div className="ct-grid ct-grid-cols-2 lg:ct-grid-cols-4 ct-gap-4">
          <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4">
            <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Active Orders</div>
            <div className="ct-text-2xl ct-font-bold">{status.activeOrders}</div>
          </div>
          <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4">
            <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Poll Interval</div>
            <div className="ct-text-2xl ct-font-bold">{status.pollIntervalMs}ms</div>
          </div>
          <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4">
            <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Total Executions</div>
            <div className="ct-text-2xl ct-font-bold">{status.totalExecutions}</div>
          </div>
          <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4">
            <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Status</div>
            <div className={`ct-text-2xl ct-font-bold ${status.paused ? 'ct-text-yellow-400' : 'ct-text-green-400'}`}>
              {status.paused ? 'Paused' : 'Running'}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
