import type { AdminPlugin, HostContext, PluginContext } from './types';
import { OverviewPanel } from './panels/OverviewPanel';
import { ProvidersPanel } from './panels/ProvidersPanel';
import { TokenRegistryPanel } from './panels/TokenRegistryPanel';
import { MonitorPanel } from './panels/MonitorPanel';

export const cedrosTradePlugin: AdminPlugin = {
  id: 'cedros-trade',
  name: 'Cedros Trade',
  version: '0.1.0',
  cssNamespace: 'cedros-trade-admin',

  groups: [
    { id: 'trading', label: 'Trading', order: 1 },
  ],

  sections: [
    { id: 'overview', label: 'Overview', group: 'trading', order: 0 },
    { id: 'providers', label: 'Swap Providers', group: 'trading', order: 1 },
    { id: 'tokens', label: 'Token Registry', group: 'trading', order: 2 },
    { id: 'monitor', label: 'Monitor', group: 'trading', order: 3 },
    { id: 'settings-trade', label: 'Trade Settings', group: 'Configuration', order: 12 },
  ],

  components: {
    'overview': OverviewPanel,
    'providers': ProvidersPanel,
    'tokens': TokenRegistryPanel,
    'monitor': MonitorPanel,
    'settings-trade': OverviewPanel, // Reuses overview for settings (can be expanded)
  },

  createPluginContext: (hostContext: HostContext): PluginContext => ({
    serverUrl: (hostContext.cedrosTrade as any)?.serverUrl ?? '',
    getAccessToken: hostContext.cedrosLogin?.getAccessToken ?? (() => null),
  }),

  checkPermission: (permission: string, hostContext: HostContext): boolean => {
    return hostContext.org?.permissions?.includes(permission) ?? true;
  },
};
