import React, { useEffect, useState, useCallback } from 'react';
import type { AdminSectionProps } from '../types';
import type { ProviderInfo } from '../../types';
import { TradeApiClient } from '../../utils/apiClient';

export function ProvidersPanel({ pluginContext }: AdminSectionProps) {
  const [providers, setProviders] = useState<ProviderInfo[]>([]);
  const api = new TradeApiClient(pluginContext.serverUrl, pluginContext.getAccessToken);

  useEffect(() => {
    api.getProviders().then(setProviders).catch(() => {});
  }, []);

  const toggle = useCallback(async (name: string, enable: boolean) => {
    const url = `${pluginContext.serverUrl}/admin/providers/${name}/${enable ? 'enable' : 'disable'}`;
    await fetch(url, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${pluginContext.getAccessToken()}` },
    });
    api.getProviders().then(setProviders);
  }, [pluginContext]);

  return (
    <div className="ct-space-y-4">
      <h2 className="ct-text-xl ct-font-semibold">Swap Providers</h2>
      <div className="ct-grid ct-gap-4">
        {providers.map(p => (
          <div key={p.name} className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4 ct-flex ct-items-center ct-justify-between">
            <div>
              <div className="ct-font-medium ct-text-[hsl(var(--cedros-foreground))] ct-capitalize">{p.name}</div>
              <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-space-x-2">
                <span>{p.health.healthy ? '● Healthy' : '○ Unhealthy'}</span>
                {p.health.latencyMs && <span>{p.health.latencyMs}ms</span>}
                {p.capabilities.gasless && <span>Gasless</span>}
                {p.capabilities.mevProtected && <span>MEV-protected</span>}
              </div>
              {p.health.error && <div className="ct-text-xs ct-text-red-400 ct-mt-1">{p.health.error}</div>}
            </div>
            <button onClick={() => toggle(p.name, !p.enabled)}
              className={`ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ${
                p.enabled ? 'ct-bg-green-500/10 ct-text-green-400' : 'ct-bg-red-500/10 ct-text-red-400'
              }`}>
              {p.enabled ? 'Enabled' : 'Disabled'}
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
